const data = $('HTML1').first().json;
const titulos = data.titulo || [];
const fechas = data.fecha || [];
const resumenes = data.resumen || [];
const resultados = [];

titulos.forEach((titulo, index) => {
    // ── 1. Limpiar título ──────────────────────────────────────────
    const txtLimpio = String(titulo)
        .split(/\[/)[0]
        .replace(/\n/g, ' ')
        .trim();

    // ── 2. Filtro de exclusión ─────────────────────────────────────
    if (txtLimpio.includes("Profesor") || txtLimpio.includes("Docente")) {
        return;
    }

    // ── 3. Fecha ───────────────────────────────────────────────────
    const fecha = (fechas[index] || "May 27, 2026").trim();

    // ── 4. Resumen ─────────────────────────────────────────────────
    let resumen = (resumenes[index] || "Contenido institucional.").toString();
    resumen = resumen.replace(/[\r\n]+/g, ' ').replace(/\s+/g, ' ').trim();
    if (resumen.includes("|") || resumen.length < 20) {
        resumen = "Noticia institucional sobre las Competencias Digitales de la UNAB.";
    }

    // ── 5. Hash (título + fecha para distinguir mismos títulos en fechas distintas) ──
    const hashInput = txtLimpio + '||' + fecha;  // ← CAMBIO
    let hash = 0;
    for (let i = 0; i < hashInput.length; i++) {
        hash = ((hash << 5) - hash) + hashInput.charCodeAt(i);
        hash = hash | 0;
    }
    const hashFinal = Math.abs(hash).toString(16);

    // ── 6. Push ────────────────────────────────────────────────────
    resultados.push({
        json: {
            text: txtLimpio,
            contentHash: hashFinal,
            metadata: {
                source_type: "web",
                title: txtLimpio,
                url: "https://www.unab.edu.co/?s=competencias+digitales",
                category: "Web Scraping",
                fecha: fecha,
                resumen: resumen,
                content_hash: hashFinal
            }
        }
    });
});

return resultados;

