// Recibimos los 6 cursos del nodo Postgres anterior
const cursos = $input.all();

// Función para formatear fecha YYYY-MM-DD desde ISO
function formatearFecha(fechaISO) {
  const fecha = new Date(fechaISO);
  const dia = String(fecha.getUTCDate()).padStart(2, '0');
  const mes = String(fecha.getUTCMonth() + 1).padStart(2, '0');
  const anio = fecha.getUTCFullYear();
  return `${dia}/${mes}/${anio}`;
}

// Función para formatear precio
function formatearPrecio(precio) {
  const num = Math.round(parseFloat(precio));
  return `$${num.toLocaleString('es-CO')}`;
}

// Agrupar cursos por pilar
const porPilar = {};
for (const item of cursos) {
  const c = item.json;
  if (!porPilar[c.pilar]) {
    porPilar[c.pilar] = [];
  }
  porPilar[c.pilar].push(c);
}

// Armar el mensaje
let mensaje = "📅 CURSOS DISPONIBLES ESTE SEMESTRE\n\n";
mensaje += "Cursos Vacacionales Intensivos 2026-1\n";
mensaje += "Inscripción: hasta el 5 de junio de 2026\n\n";
mensaje += "━━━━━━━━━━━━━━━━━━━\n\n";

for (const pilar in porPilar) {
  mensaje += `🎓 ${pilar.toUpperCase()}\n\n`;

  for (const curso of porPilar[pilar]) {
    mensaje += `📘 ${curso.nombre_curso}\n`;
    mensaje += `🔢 NRC: ${curso.nrc}\n`;
    mensaje += `🏷️ Modalidad: ${curso.modalidad}\n`;
    mensaje += `🕐 Horario: ${curso.horario}\n`;
    mensaje += `📆 ${formatearFecha(curso.fecha_inicio)} al ${formatearFecha(curso.fecha_fin)}\n`;
    mensaje += `💰 ${formatearPrecio(curso.precio)} COP\n\n`;
  }

  mensaje += "━━━━━━━━━━━━━━━━━━━\n\n";
}

mensaje += "📋 CÓMO INSCRIBIRTE:\n\n";
mensaje += "1. Ingresa a Cosmos con tu cuenta UNAB\n";
mensaje += "2. Haz clic en Alumnos\n";
mensaje += "3. Selecciona Inscripción\n";
mensaje += "4. Elige el período académico\n";
mensaje += "5. Selecciona Agregar/Eliminar Cursos\n";
mensaje += "6. Registra el NRC del curso que deseas\n\n";
mensaje += "💳 CÓMO PAGAR:\n\n";
mensaje += "1. En Cosmos, selecciona Cupón de pago\n";
mensaje += "2. Entra a Cupones de pagos\n";
mensaje += "3. Selecciona Consultar en Matrícula\n";
mensaje += "4. Genera el cupón o paga en línea por PSE\n\n";
mensaje += "⚠️ Recuerda: los cursos solo se abren si cumplen con el número mínimo de estudiantes inscritos y pago registrado dentro de las fechas establecidas.\n\n";
mensaje += "¿Necesitas más ayuda? Escribe /info";

// Devolvemos el mensaje en el campo 'output' (igual que los Set anteriores)
return [{ json: { output: mensaje } }];

// El CSV viene en el campo 'data' del HTTP Request
const csvRaw = $input.first().json.data || $input.first().json.body || $input.first().json;

// Convertir a string si llega como objeto
const csvText = typeof csvRaw === 'string' ? csvRaw : JSON.stringify(csvRaw);

// Parsear el CSV manualmente
const lineas = csvText.split('\n').filter(l => l.trim() !== '');

// La primera línea son los headers
const headers = lineas[0].split(',').map(h => h.trim().toLowerCase());

// Parsear filas
const eventos = [];
for (let i = 1; i < lineas.length; i++) {
  const valores = lineas[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
  const evento = {};
  headers.forEach((h, idx) => {
    evento[h] = valores[idx] || '';
  });
  eventos.push(evento);
}

// Función robusta: convierte cualquier formato de fecha a un número para ordenar
function fechaANumero(fechaStr) {
  if (!fechaStr) return 0;

  // Formato YYYY-MM-DD (ISO)
  let match = fechaStr.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (match) {
    return parseInt(match[1] + match[2] + match[3]);
  }

  // Formato DD/MM/YY o DD/MM/YYYY
  match = fechaStr.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})/);
  if (match) {
    let anio = match[3];
    if (anio.length === 2) anio = '20' + anio; // 26 -> 2026
    const mes = match[2].padStart(2, '0');
    const dia = match[1].padStart(2, '0');
    return parseInt(anio + mes + dia);
  }

  return 0;
}

// Función para formatear fecha bonita
function formatearFecha(fechaStr) {
  if (!fechaStr) return fechaStr;

  // Si ya está en DD/MM/YY o DD/MM/YYYY, normalizar a DD/MM/YYYY
  let match = fechaStr.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})/);
  if (match) {
    let anio = match[3];
    if (anio.length === 2) anio = '20' + anio;
    const mes = match[2].padStart(2, '0');
    const dia = match[1].padStart(2, '0');
    return `${dia}/${mes}/${anio}`;
  }

  // Si está en YYYY-MM-DD
  match = fechaStr.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (match) {
    return `${match[3]}/${match[2]}/${match[1]}`;
  }

  return fechaStr;
}

// Ordenar eventos por fecha real
eventos.sort((a, b) => {
  return fechaANumero(a.fecha) - fechaANumero(b.fecha);
});

// Armar el mensaje
let mensaje = "📅 CALENDARIO ACADÉMICO DEL CCD\n\n";
mensaje += "Fechas importantes del Centro de Competencias Digitales:\n\n";
mensaje += "━━━━━━━━━━━━━━━━━━━\n\n";

for (const evento of eventos) {
  const nombre = evento.evento || 'Evento';
  const fecha = formatearFecha(evento.fecha);
  const descripcion = evento.descripcion || '';
  const tipo = evento.tipo || '';
  const pilar = evento.pilar || '';

  mensaje += `📌 ${nombre}\n`;
  mensaje += `📆 ${fecha}\n`;
  if (descripcion) mensaje += `📝 ${descripcion}\n`;
  if (tipo) mensaje += `🏷️ Tipo: ${tipo}\n`;
  if (pilar && pilar.toLowerCase() !== 'todos' && pilar.toLowerCase() !== 'general') {
    mensaje += `🎓 ${pilar}\n`;
  }
  mensaje += `\n`;
}

mensaje += "━━━━━━━━━━━━━━━━━━━\n\n";
mensaje += "💡 Para más información sobre algún evento, pregúntame directamente.\n";
mensaje += "📧 Contacto: ccdigital@unab.edu.co";

return [{ json: { output: mensaje } }];

