const filas = $input.all();

// Obtener el ID que el usuario consultó
const idConsultado = $('Telegram Trigger').first().json.message.text;

// Caso 1: el ID no existe en la BD (0 filas O primera fila con nombre null)
if (filas.length === 0 || !filas[0].json.nombre_completo) {
  const mensaje = `🤔 No encontré ningún estudiante con el ID ${idConsultado}.\n\n` +
                  "Verifica que el ID esté correcto y vuelve a intentar.\n\n" +
                  "Si crees que es un error, comunícate con el CCD:\n" +
                  "📧 ccdigital@unab.edu.co\n" +
                  "📞 (607) 6436111, ext. 1807 / 1644\n\n" +
                  "Para volver a consultar, escribe /miscursos";
  return [{ json: { output: mensaje } }];
}

// Tomar los datos del estudiante de la primera fila
const primerRegistro = filas[0].json;
const nombreEstudiante = primerRegistro.nombre_completo;
const programa = primerRegistro.programa_academico;
const semestre = primerRegistro.semestre_actual;

// Filtrar solo cursos reales (donde nombre_materia no es null)
const cursosReales = filas.filter(f => f.json.nombre_materia !== null && f.json.nombre_materia !== undefined);

// Caso 2: el estudiante existe pero no tiene cursos del CCD
if (cursosReales.length === 0) {
  let mensaje = `📚 CURSOS DEL CCD\n\n`;
  mensaje += `Datos del estudiante ${idConsultado}:\n\n`;
  mensaje += `👤 ${nombreEstudiante}\n`;
  mensaje += `🎓 Programa: ${programa}\n`;
  mensaje += `📖 Semestre actual: ${semestre}\n\n`;
  mensaje += `━━━━━━━━━━━━━━━━━━━\n\n`;
  mensaje += `Este estudiante aún no tiene cursos del CCD registrados.\n\n`;
  mensaje += `💡 Para ver los cursos disponibles este semestre, escribe /oferta\n`;
  mensaje += `🏅 Para conocer la Insignia de Competencias Digitales, escribe /insignia\n\n`;
  mensaje += `⚠️ Aviso: la información mostrada corresponde al ID ${idConsultado}. La consulta es responsabilidad del usuario que la solicita.`;
  return [{ json: { output: mensaje } }];
}

// Caso 3: el estudiante existe y tiene cursos — agrupar por pilar
const porPilar = {};
for (const f of cursosReales) {
  const c = f.json;
  const pilar = c.pilar || 'Sin pilar';
  if (!porPilar[pilar]) {
    porPilar[pilar] = [];
  }
  porPilar[pilar].push(c);
}

// Detectar pilares completados y faltantes
const pilaresCompletados = Object.keys(porPilar);
const todosPilares = [
  'Competencias Digitales Básicas',
  'Analítica y Contenido Digital',
  'Transformación Digital'
];
const pilaresFaltantes = todosPilares.filter(p => !pilaresCompletados.includes(p));

// Armar mensaje
let mensaje = `📚 CURSOS DEL CCD\n\n`;
mensaje += `Historial académico del estudiante ${idConsultado}:\n\n`;
mensaje += `👤 ${nombreEstudiante}\n`;
mensaje += `🎓 Programa: ${programa}\n`;
mensaje += `📖 Semestre actual: ${semestre}\n\n`;
mensaje += `━━━━━━━━━━━━━━━━━━━\n\n`;

for (const pilar in porPilar) {
  mensaje += `🎯 ${pilar.toUpperCase()}\n\n`;
  for (const curso of porPilar[pilar]) {
    const nota = curso.nota || 'Sin nota registrada';
    mensaje += `✅ ${curso.nombre_materia}\n`;
    mensaje += `   📅 Cursado: ${curso.periodo_tomado}\n`;
    mensaje += `   📊 Nota: ${nota}\n\n`;
  }
}

mensaje += `━━━━━━━━━━━━━━━━━━━\n\n`;

// Resumen del progreso hacia la insignia
if (pilaresFaltantes.length === 0) {
  mensaje += `🏅 ¡FELICITACIONES! Este estudiante ha completado los tres pilares.\n`;
  mensaje += `Tiene derecho a la Insignia de Competencias Digitales.\n\n`;
  mensaje += `💡 Si tienes dudas sobre cómo recibirla, escribe /info\n\n`;
} else {
  mensaje += `🎯 Para obtener la Insignia faltan estos pilares:\n\n`;
  for (const p of pilaresFaltantes) {
    mensaje += `• ${p}\n`;
  }
  mensaje += `\n💡 Para ver cursos disponibles este semestre, escribe /oferta\n\n`;
}

mensaje += `⚠️ Aviso: la información mostrada corresponde al ID ${idConsultado}. La consulta es responsabilidad del usuario que la solicita.`;

return [{ json: { output: mensaje } }];
